INSERT INTO atividade (atividade_pergunta ,atividade_resposta, atividade_tipo,FK_id_aula) VALUES
('Qual destas opções melhor descreve a Inteligência Artificial no seu cotidiano?', 'Um assistente que ajuda a realizar tarefas e encontrar informações mais rápido.', 'Múltipla Escolha', 1),
('Para que serve o campo de digitação (prompt) no ChatGPT?', 'Para escrever perguntas ou comandos que você quer que a IA responda.', 'Dissertativa', 2),
('Ao usar IA para criar um currículo, o que é mais importante conferir?', 'Se todas as informações e experiências profissionais estão corretas e verdadeiras.', 'Múltipla Escolha', 3),
('Se você receber um link suspeito no WhatsApp dizendo ser do banco, qual a primeira atitude?', 'Não clicar e verificar a informação em um canal oficial ou usar uma IA de segurança.', 'Múltipla Escolha', 4),
('Verdadeiro ou Falso: A IA pode ser usada para praticar respostas de uma entrevista de emprego.', 'Verdadeiro', 'Verdadeiro/Falso', 5),
('Como a IA pode ajudar a lidar com uma caixa de e-mails lotada?', 'Resumindo os pontos principais das mensagens mais longas.', 'Dissertativa', 6),
('Qual comando você daria a uma IA para gerar uma imagem de um jardim ao pôr do sol?', 'Crie uma imagem realista de um jardim com flores coloridas durante o pôr do sol.', 'Prática', 7),
('A IA pode substituir o seu gerente do banco para tomar decisões financeiras críticas?', 'Não, ela serve apenas como ferramenta de auxílio e organização de dados.', 'Verdadeiro/Falso', 8),
('Como identificar se uma notícia encontrada na internet pode ser uma "Fake News"?', 'Verificando a fonte, a data e se outros sites confiáveis confirmam a informação.', 'Dissertativa', 9),
('Qual o principal benefício de um idoso aprender a usar IA hoje?', 'Manter-se conectado com o mundo moderno e ter mais autonomia digital.', 'Múltipla Escolha', 10);